//import {getStore,setStore} from "@ai/nc-ui-api/src/store";
import envConfig from "./envConfig";
let cmps = {}
if(typeof nc !== 'undefined' && nc.cmp) {
    cmps = nc.cmp
}
export default function(menusRouter, moduleName) {
  let router = [];
    let userInfo = nc.util.getStore({name:"userInfo"});
  function getUrlParams(paramStr) {
    let paramsObj = {};
    if (paramStr.indexOf("?") != -1) {
      let str = paramStr.split("?")[1];
      let paramArr = str.split("&");
      for(let i = 0; i < paramArr.length; i ++) {
        paramsObj[paramArr[i].split("=")[0]] = unescape(paramArr[i].split("=")[1]);
      }
    }
    return paramsObj;
  }
  
  console.log(`[Demo-Lite] Router initializing with moduleName: ${moduleName}`);
  console.log(`[Demo-Lite] Received menusRouter:`, menusRouter);

  // 动态路由
  for (let item of menusRouter){
    // Skip agent dynamic route to avoid module loading error; use manual route below
    if (moduleName === 'demo' && item.path === '/demo/agent') {
      continue;
    }
    let props = {};
    let route = {
      name: item.label,
      path: item.path,
      props: props,
      query:{},
      meta: {
        keepAlive: Number(item['keepAlive']) === 1,
        moduleName: moduleName,
        name: item.label,
        resource: item.resource ? item.resource : [],
          defaultParams : {
              grayMode: (envConfig.grayMode) == undefined ? "" : envConfig['grayMode']
          },
        inputParams:{
            userId:userInfo ? userInfo.id : '',
            tenantId:userInfo ? userInfo.tenantId : ''
        }
      }
    }
    
    let realPath = item.path.replace('/' + moduleName,'');
    let vueName = realPath.replace('/',''); // Remove leading slash
    
    let fromCmp = false;
    let cmpName = vueName;
    
    // Handle query params in path
    if(vueName && vueName.indexOf('?') != -1){
        realPath = realPath.split("?")[0];
        cmpName = vueName.split("?")[0];
        let params = getUrlParams(item.path);
        if(params){
            route.props = params;
            route.meta.inputParams=Object.assign(route.meta.inputParams,params);
        }
    }
    
    // Check for Component mapping (external components)
    let arr = cmpName.split("/");
    cmpName = arr[0];
     let cmp = cmps[cmpName];
     if(cmp) {//说明是组件包中的组件
        fromCmp = true;
        route.component = cmp;
     }
     
     // Handle UUID or extra params in path segments
     if(arr.length>1){
        route.props['uuid']= arr[1];
     }
     if(arr && arr.length>1){
          if(arr[arr.length-1].indexOf("=")>=0){
              //解析参数
              let params =getUrlParams( "?"+arr[arr.length-1]);
              if(params){
                  route.props = Object.assign(route.props,params);
                  route.meta.inputParams=Object.assign(route.meta.inputParams,params);
              }
              realPath=realPath.substring(0,realPath.lastIndexOf("/"));
          }
      }
      route.path =item.path.split("?")[0];

    if(!fromCmp) {
      // Re-calculate vueName from cleaned realPath
      vueName = realPath; 
      
      // ADAPTATION: If the module is 'demo' and path doesn't start with /demo/, prepend it.
      // This allows menu path /demo/Menu1 to resolve to ../views/demo/Menu1.vue
      if (moduleName === 'demo' && !vueName.startsWith('/demo/')) {
          vueName = '/demo' + vueName;
      }
      
      console.log(`[Demo-Lite] Registering route: ${route.path} -> views${vueName}.vue`);

      route.component= () => import(
        /* webpackChunkName: "views/[request]" */
        `../views${vueName}`
      ).catch(e => {
          console.error(`[Demo-Lite] Failed to load component: ../views${vueName}`, e);
      });
    }

    router.push(route);
  }
  
  // Manual route for Ops Agent (Fallback if menu config fails or to test directly)
  // Now pointing to agent.vue to match the renamed file
  router.push({
    name: 'Ops Agent',
    path: '/demo/agent',
    meta: {
      moduleName: moduleName,
      name: 'Ops Agent',
      keepAlive: true
    },
    component: () => import(/* webpackChunkName: "views/views-demo-agent" */ '../views/demo/agent.vue')
  });

  return router;
}
