/* 模块的初始化逻辑 */
// import {GqlApi} from '@ai/nc-ui-api';
import envConfig from "./envConfig";
/**
 * 初始化入口方法
 */
export function init() {
    //初始化环境变量
    window.nc = window.nc || {};
    window.nc.Default = window.nc.Default || {};
    window.nc.Default.serviceName = window.nc.Default.serviceName || {};
    let grayMode = envConfig.grayMode;
    let headersParmas = {};
    if (grayMode) {
        headersParmas = {"grayMode":grayMode};
    }
    for (let key in envConfig.serviceName) {
        //if (!(key in nc.Default.serviceName)) {
            if(key != 'r') {
                nc.Default.serviceName[key] = envConfig.serviceName[key]
                //初始化GqlApi调用客户端
                // Check if GqlApi exists before using it
                // if (typeof GqlApi !== 'undefined') {
                //      nc[`${key.toLowerCase()}api`] = new GqlApi(nc.Default.serviceName[key],'',headersParmas);
                // }
            }
        //}
    }
    console.info("合并后的服务集serviceName-------" + JSON.stringify(nc.Default.serviceName));
}

/**
 * 安装使用工具包
 */
export function install() {
    if(nc['Vue'] && arguments.length > 0) {
        [...arguments].forEach(item => {
            nc['Vue'].use(item)
        })
    }
}

/**
 * 引入样式文件
 */
export function importStyle() {
    if(arguments.length > 0) {
        [...arguments].forEach(item => {
            eval(`import ${item}`)
        })
    }
}

/**
 * 引入灰度标签
 */
export function importGrayMode() {
    let grayMode = envConfig.grayMode;
    if(window.axios && grayMode) {
        axios.interceptors.request.use(config => {
            config.headers['grayMode'] = grayMode;
            return config
        }, error => {
            console.error(error);
        })
    }
}
